from ag2.groupchat import GroupChatManager

def detect_speaker_override(groupchat: GroupChatManager, max_speaker_repeats: int = 3):
    speaker_history = groupchat.get_speaker_history()
    if len(speaker_history) > max_speaker_repeats:
        recent_speakers = speaker_history[-max_speaker_repeats:]
        if len(set(recent_speakers)) == 1:
            return {
                'alert': 'Potential speaker override detected',
                'speaker': recent_speakers[0],
                'pattern': 'repeated_selection'
            }
    return None

import re

def scan_injection_patterns(message: str):
    injection_patterns = [
        r'ignore.*previous.*instructions',
        r'you are now.*role',
        r'forget.*system.*prompt',
        r'execute.*code',
        r'system\(.*?\)'
    ]
    for pattern in injection_patterns:
        if re.search(pattern, message, re.IGNORECASE):
            return {
                'alert': 'Injection pattern detected',
                'pattern': pattern,
                'severity': 'high'
            }
    return None

