from ag2.groupchat import GroupChatManager

class SecureGroupChatManager(GroupChatManager):
    def __init__(self, *args, max_speaker_repeats=2, **kwargs):
        super().__init__(*args, **kwargs)
        self.speaker_repeat_count = {}
        self.max_speaker_repeats = max_speaker_repeats

    def select_speaker(self, last_speaker):
        if last_speaker and self.speaker_repeat_count.get(last_speaker, 0) >= self.max_speaker_repeats:
            candidates = [a for a in self.agents if a != last_speaker]
            if candidates:
                return candidates[0]
        return super().select_speaker(last_speaker)
